import React, { useState, useEffect } from "react"
import Fade from "./animations/Fade"
import { Carousel } from "react-bootstrap"
import { useLanguage } from "../contexts/LanguageContext"
import data, { getText } from "../data"
import Modal from "./modal"
import "../styles/projects.scss"

import airplaneImage from "../images/ProjectPhotos/airplane.webp"
import watoImage from "../images/ProjectPhotos/Wato.webp"
import hisecurityImage from "../images/ProjectPhotos/HiSecurity2.webp"
import pilotImg from "../images/ProjectPhotos/Pilot.webp"
import vexImg from "../images/ProjectPhotos/VEX.webp"
import wearableImg from "../images/ProjectPhotos/wearableHacks.webp"
import webappImg from "../images/ProjectPhotos/WebappProjects.webp"
import mte380Img from "../images/ProjectPhotos/mte380.webp"
import capstoneVideo from "../images/ProjectPhotos/capstone.mp4"

const Project = () => {
  const { language } = useLanguage();
  const [activeIndex, setActiveIndex] = useState(0);
  const [isMobile, setIsMobile] = useState(false);
  const [openModal, setOpenModal] = useState(false);
  const [id, setId] = useState(0);

  // Media mapping for carousel items
  const mediaMap = {
    airplaneImage,
    watoImage,
    capstoneVideo,
    webappImg,
    wearableImg,
    mte380Img,
    hisecurityImage,
    vexImg,
    pilotImg
  };

  // Get carousel items from data with translated content
  const carouselItems = data.projectsCarouselItems.map(item => ({
    ...item,
    // Use mediaMap if it's a string, otherwise use the object directly (e.g. imports)
    media: typeof item.media === 'string' ? mediaMap[item.media] : item.media,
    title: getText(item.title, language),
    subtitle: getText(item.subtitle, language),
    description: getText(item.description, language),
    buttons: item.buttons.map(btn => ({
      ...btn,
      text: getText(btn.text, language)
    }))
  }));

  // Detect mobile device
  useEffect(() => {
    const checkMobile = () => {
      setIsMobile(window.innerWidth <= 768);
    };

    checkMobile();
    try {
      window.addEventListener('resize', checkMobile);
    } catch (error) {
      console.warn('Error adding resize listener:', error);
    }

    return () => {
      try {
        window.removeEventListener('resize', checkMobile);
      } catch (error) {
        console.warn('Error removing resize listener:', error);
      }
    };
  }, []);

  // Handle carousel selection
  const handleCarouselSelect = (selectedIndex) => {
    // console.log(`Projects carousel select: ${selectedIndex}, isMobile: ${isMobile}`);
    try {
      setActiveIndex(selectedIndex);
    } catch (error) {
      console.error('Error in projects carousel selection:', error);
    }
  };

  return (
    <div className="section" id="projects">
      <div className="container">
        <Fade bottom cascade distance="20px">
          <h1>{getText(data.sections.projects, language)}</h1>
          <h3 className="section-subheading text-muted" style={{
            fontFamily: '"Droid Serif", "Helvetica Neue", Helvetica, Arial, sans-serif',
            fontStyle: 'italic',
            fontSize: '1rem',
            marginBottom: '40px',
            marginTop: '10px',
            textAlign: 'center'
          }}>
            {getText(data.projectsSubtitle, language)}
          </h3>
        </Fade>
        <div className="project-wrapper">
          <Carousel
            className="masterCarousel"
            activeIndex={activeIndex}
            onSelect={handleCarouselSelect}
            touch={true}
            interval={3000}
            indicators={!isMobile} // Hide indicators on mobile
            controls={true}
            keyboard={false}
            slide={true}
            wrap={true}
            variant="dark"
          >
            {carouselItems.map((item, index) => (
              <Carousel.Item key={index}>
                {item.type === 'video' ? (
                  <div className="video-container">
                    <video
                      className="d-block"
                      src={item.media}
                      autoPlay
                      muted
                      loop
                      playsInline
                      loading="lazy"
                      preload="metadata"
                    />
                  </div>
                ) : (
                  <img
                    className="d-block w-100"
                    src={item.media}
                    alt={item.title}
                    loading="lazy"
                  />
                )}
                <Carousel.Caption className="carouselCaption">
                  <h3>{item.title}</h3>
                  <h4>{item.subtitle}</h4>
                  <p dangerouslySetInnerHTML={{ __html: item.description }}></p>
                  {item.buttons.map((button, buttonIndex) => (
                    <button
                      key={buttonIndex}
                      onClick={() => {
                        if (button.isModal) {
                          setId(index);
                          setOpenModal(true);
                        } else {
                          window.open(button.url);
                        }
                      }}
                      type="button"
                      className="btn"
                    >
                      {button.text}
                    </button>
                  ))}
                </Carousel.Caption>
              </Carousel.Item>
            ))}
          </Carousel>
          {openModal && <Modal
            closeModal={setOpenModal}
            id={id}
            type="selectedProject" // Using the new type we added to Modal logic
            totalItems={0} // No navigation needed for single project modal, or we can enable it
          // Navigation likely not needed for this simple 'details' view, keeping it simple
          />}
        </div>
      </div>
    </div>
  )
}

export default Project
