import React, { useEffect, useCallback, useState } from "react"
import { useLanguage } from "../contexts/LanguageContext"
import { getText } from "./../data"
import "./../css/modal.scss" // Reuse existing modal styles

export default function DetailedModal({ closeModal, content, title, image }) {
    const { language } = useLanguage();
    const [isClosing, setIsClosing] = useState(false);

    // Enhanced close function with animation
    const handleClose = useCallback(() => {
        setIsClosing(true);
        // Wait for animation to complete before actually closing
        setTimeout(() => {
            closeModal(false);
        }, 300); // Match the CSS animation duration
    }, [closeModal]);

    // Keyboard navigation
    useEffect(() => {
        const handleKeyDown = (e) => {
            if (e.key === 'Escape') {
                e.preventDefault();
                handleClose();
            }
        };

        document.addEventListener('keydown', handleKeyDown);
        return () => {
            document.removeEventListener('keydown', handleKeyDown);
        };
    }, [handleClose]);

    useEffect(() => {
        document.body.classList.add('modal-open');
        return () => {
            document.body.classList.remove('modal-open');
        };
    }, []);

    return (
        <>
            <div
                className={`modalBackground ${isClosing ? 'closing' : ''}`}
                onClick={handleClose}
                role="button"
                tabIndex={0}
            ></div>
            <div className={`modalContainer ${isClosing ? 'closing' : ''}`}>
                <div className="titleCloseBtn">
                    <button onClick={handleClose}>
                        <h3>&#215;</h3>
                    </button>
                </div>

                <div className="title">
                    <h1>{getText(title, language)}</h1>
                </div>

                <div className="body">
                    {image && (
                        <div className="modal-media-wrapper" style={{ flex: 1, display: 'flex', flexDirection: 'column' }}>
                            <img
                                src={image}
                                className="img-fluid modal-media"
                                alt={getText(title, language)}
                                loading="lazy"
                                style={{ width: '100%', height: 'auto', marginBottom: '0' }}
                            />
                            {content.caption && (
                                <p className="img-caption" style={{
                                    textAlign: 'center',
                                    fontStyle: 'italic',
                                    fontSize: '0.9rem',
                                    color: '#6c757d',
                                    marginTop: '8px',
                                    marginBottom: '0',
                                    fontWeight: '400',
                                    fontFamily: 'inherit'
                                }}>
                                    {getText(content.caption || caption, language)}
                                </p>
                            )}
                        </div>
                    )}
                    {/* Render HTML content safely */}
                    <div className="text-content" dangerouslySetInnerHTML={{ __html: getText(content.html || content, language) }} style={{ width: '100%' }} />
                </div>
            </div>
        </>
    )
}
